<script lang="ts">
  const html: string = "<h1>Statistic</h1>\n\n<p>A statistic is a numeric value display with title, optional prefix, and optional suffix. It groups the components into a single landmark with <code>role=\"group\"</code> and a synthesized <code>aria-label</code>.</p>\n\n<p>Use it for dashboards, KPIs, summary cards, and any place a single prominent number must be paired with a short label.</p>\n\n<h2>Implementation Notes</h2>\n\n<ul>\n<li>Renders a <code>&lt;div class=\"statistic\" role=\"group\"&gt;</code> container</li>\n<li><code>title</code> is <strong>required</strong> and renders in <code>&lt;div class=\"statistic-title\"&gt;</code></li>\n<li><code>value</code> is <strong>required</strong> and renders inside <code>&lt;div class=\"statistic-value\"&gt;</code></li>\n<li>Optional <code>prefix</code> slot renders in <code>&lt;span class=\"statistic-prefix\"&gt;</code></li>\n<li>Optional <code>suffix</code> slot renders in <code>&lt;span class=\"statistic-suffix\"&gt;</code></li>\n<li><code>aria-label</code> defaults to <code>\"{title}: {value}\"</code> and may be overridden via the <code>label</code> prop</li>\n<li>Consumer formats numeric values before passing them as <code>value</code></li>\n</ul>\n\n<h2>Props</h2>\n\n<ul>\n<li><code>title</code>: string (<strong>required</strong>) -- statistic label/heading</li>\n<li><code>value</code>: string (<strong>required</strong>) -- pre-formatted value text</li>\n<li><code>prefix</code>: slot (optional) -- element before the value (e.g., currency symbol)</li>\n<li><code>suffix</code>: slot (optional) -- element after the value (e.g., unit or %)</li>\n<li><code>label</code>: string (optional) -- aria-label override</li>\n<li><code>...restProps</code>: any additional HTML attributes</li>\n</ul>\n\n<h2>Usage</h2>\n\n<pre><code class=\"language-html\">&lt;Statistic title=\"Active users\" value=\"12,345\" suffix=\"users\" /&gt;</code></pre>\n\n<pre><code class=\"language-html\">&lt;Statistic title=\"Revenue\" value=\"2,400\" prefix=\"$\" suffix=\"K\" /&gt;</code></pre>\n\n<pre><code class=\"language-html\">&lt;Statistic\n  title=\"Conversion\"\n  value=\"4.2\"\n  suffix=\"%\"\n  label=\"Conversion rate is 4.2 percent\"\n/&gt;</code></pre>\n\n<h2>Keyboard Interactions</h2>\n\n<ul>\n<li>None — passive display element.</li>\n</ul>\n\n<h2>ARIA</h2>\n\n<ul>\n<li><code>role=\"group\"</code> groups the title and value into a single labeled region</li>\n<li><code>aria-label</code> provides the spoken summary, defaulting to <code>\"{title}: {value}\"</code></li>\n</ul>\n\n<h2>When to Use</h2>\n\n<ul>\n<li>Use to highlight a single number with a label, especially on dashboards or summary cards.</li>\n<li>Use with prefix or suffix for currency, units, or percentages.</li>\n</ul>\n\n<h2>When Not to Use</h2>\n\n<ul>\n<li>Do not use for tabular data — use DataTable.</li>\n<li>Do not use for free-form text content — use BodyText.</li>\n<li>Do not use when the value needs to update with live screen-reader announcements — use a status region.</li>\n</ul>\n\n<h2>Headless</h2>\n\n<p>Renders semantic group markup with no styling. Consumer formats the value, sizes the type, and chooses any visual emphasis.</p>\n\n<h2>Styles</h2>\n\n<p>Consumer CSS targets <code>statistic</code>, <code>statistic-title</code>, <code>statistic-value</code>, <code>statistic-prefix</code>, and <code>statistic-suffix</code>. Use larger type and stronger weight for the value than the title.</p>\n\n<h2>Testing</h2>\n\n<ul>\n<li>Verify the component renders a <code>&lt;div&gt;</code> element with class <code>statistic</code></li>\n<li>Verify <code>role=\"group\"</code> is set</li>\n<li>Verify <code>aria-label</code> defaults to <code>\"{title}: {value}\"</code> when <code>label</code> is not provided</li>\n<li>Verify <code>aria-label</code> equals the <code>label</code> prop when provided</li>\n<li>Verify the title renders inside <code>&lt;div class=\"statistic-title\"&gt;</code></li>\n<li>Verify the value renders inside <code>&lt;div class=\"statistic-value\"&gt;</code></li>\n<li>Verify the prefix renders inside <code>&lt;span class=\"statistic-prefix\"&gt;</code> only when provided</li>\n<li>Verify the suffix renders inside <code>&lt;span class=\"statistic-suffix\"&gt;</code> only when provided</li>\n</ul>\n\n<h2>Advice</h2>\n\n<ul>\n<li><strong>Designers</strong>: Keep titles short and values pre-formatted. Use suffix/prefix for units rather than embedding them in <code>value</code>.</li>\n<li><strong>Developers</strong>: Format numbers in the consumer (locale, separators, decimals) before passing as the <code>value</code> prop.</li>\n</ul>\n\n<h2>Related components</h2>\n\n<ul>\n<li><code>meter</code> — a gauge displaying a scalar value within a known range</li>\n<li><code>sparkline</code> — a small inline chart showing a data trend</li>\n</ul>\n\n<h2>References</h2>\n\n<ul>\n<li>WAI-ARIA Group Role: https://www.w3.org/TR/wai-aria-1.2/#group</li>\n<li>Ant Design Statistic: https://ant.design/components/statistic</li>\n</ul>";
  // BEGIN auto-generated component example consts
  const demoHtml: string = "<div class=\"statistic\" aria-label=\"a numeric value display with title, prefix, and suffix\">Statistic</div>";
  const svelteSource: string = "// In your Svelte component:\nimport Statistic from \"lily-design-system-svelte-headless/components/Statistic/Statistic.svelte\";\n\n<Statistic>\n  <!-- content -->\n</Statistic>\n";
  // END auto-generated component example consts
</script>

